      "the_foundational_ies_practice_guide_5_": "ናይ መሰረታዊ IES Practice Guide። ናይ ቁጽሪ-መስመር ሞዴል ማእከላዊ ኣጠቓቕማ ሓዊሱ 5 ምኽርታት።",
      "origin_of_the_enactive_concrete_iconic": "ናይ enactive (ግሁድ) → iconic (ወካሊ) → symbolic (ረቂቕ) መስርሕ ምንጪ CRA ዝኾነ።",
      "cra_in_special_education_context_evide": "CRA ኣብ ፍሉይ ትምህርቲ ኣቀማምጣ። ንቅደም ተኸተል መርተዖ።",
      "origin_of_the_translation_model_moving": "ናይ ትርጉም ሞዴል ምንጪ — ኣብ መንጎ symbolic፣ ምስላዊ፣ ቃላዊ፣ manipulatives፣ ከምኡውን ናይ ሓቀኛ ዓለም ኣቀማምጣታት ምንቅስቓስ።",
      "documents_the_whole_number_bias_miscon": "ናይ \"ምሉእ-ቁጽሪ ኣድልዎ\" ግጉይ ኣረኣእያ ይምዝግብ።",
      "maps_how_students_construct_fraction_m": "ተመሃሮ ናይ ክፋል ዓቐን ብግዜ ብኸመይ ከም ዝሃንጹ ካርታ ይገብር።",
      "synthesizes_the_cognitive_challenges_o": "ናይ ክፋል ስሌት ናይ ኣእምሮ ብድሆታት የወሃህድ።",
      "foundational_text_for_the_number_talk_": "ን Number Talk ስርዓት መሰረታዊ ጽሑፍ።",
      "growth_mindset_applied_to_mathematics_": "ናይ ዕቤት ኣተሓሳስባ ኣብ ናይ ሒሳብ ትምህርቲ እተተግበረ።",
      "original_cuisenaire_rod_system_that_be": "ንክፋል ስቲሪፕ prototype ዝኾነ በዅሪ ናይ Cuisenaire በትሪ ስርዓት።",
      "meta_analysis_showing_positive_effects": "ናይ manipulatives ኣብ ናይ ሒሳብ ዓወት ኣወንታዊ ጽልዋ ዘርኢ Meta-analysis።",
      "effects_of_ed_tech_integration_on_math": "ናይ ed-tech ውህደት ኣብ ናይ ሒሳብ ትምህርቲ ዘለዎ ጽልዋ።",
      "worked_example_effect_why_showing_solu": "ናይ worked-example ጽልዋ — መፍትሒታት ምርኣይ ንጀመርቲ ተመሃሮ ካብ ናይ ልምምድ ጸገማት ጥራይ ንላዕሊ ስለምንታይ ዝያዳ ውጽኢታዊ ከም ዝኸውን።",
      "research_citations": "📚 ናይ መጽናዕቲ ጥቕስታት",
