      "when_do_birds_migrate": "📅 ኣዕዋፍ መዓስ ይፈልሳ?",
      "migration_timing_varies_dramatically_b": "ግዜ ፍልሰት ብመሰረት ዓሌት ኣዝዩ ይፈላለ:",
      "early_spring_waterfowl_ducks_geese_hea": "መጀመርታ ጽድያ: ናይ ማይ ኣዕዋፍ (ደርሆ ማይ፣ ኣባህራት) ንምፍያ በረድ ስዒበን ናብ ሰሜን ይኸዳ። Red-winged Blackbirds ናብ ርሑሳት መሬታት ይምለሳ።",
      "peak_spring_warblers_vireos_tanagers_f": "ልዑል ጽድያ: Warblers, vireos ን tanagers ን ንሰሜን ይመልእኦ። መብዛሕትኤን ደረፍቲ ኣዕዋፍ ብለይቲ ይፈልሳ። ኣብ ልዑል ለይትታት ካብ 500 ሚልዮን ንላዕሊ ኣዕዋፍ ኣብ ሰማይ ኣለዋ።",
      "shorebirds_start_south_some_species_fa": "ናይ ገምገም ባሕሪ ኣዕዋፍ ናብ ደቡብ ይጅምራ — ገለ ዓሌታት ኣብ መፍረ ቦታታት “ይፈሽላ” ኣብ መጀመርታ ሓምለ ድማ ክምለሳ ይጅምራ። ዓበይቲ መብዛሕትኡ ግዜ ቅድሚ ጨጫውቲ ይኸዳ።",
      "peak_fall_raptors_ride_thermals_along_": "ልዑል ቀውዒ: ኣዳናይ ኣዕዋፍ ኣብ ሰንሰለታት ኣኽራን ማዕበላት ሙቐት ይጋልባ። ደረፍቲ ኣዕዋፍ ዝሑላት ገጻት ስዒበን ናብ ደቡብ ይኸዳ። ኣባህራት ብለይቲ ኣብ ኣሰራርዓ V ይበርራ።",
      "photoperiod_day_length_is_the_primary_": "ናይ ብርሃን ግዜ (ንውሓት መዓልቲ) ቀንዲ መላዒ ፍልሰት እዩ። ኣብ ቀውዒ መዓልትታት ክሓጽራ ከለዋ፣ ሆርሞናት ን“Zugunruhe” — ዘይምዕራፍ ፍልሰት — የለዓዕላ ኣዕዋፍ ድማ ናይ ስብሒ ዕቑር (ብልዕሊ ዓቐን ምብላዕ) ክእክባ ይጅምራ፣ ሓድሓደ ግዜ ክብደት ኣካል ዕጽፊ ይገብራ።",
      "stopover_ecology": "⛺ ስነ-ኣከባቢ ናይ ደው መበሊ ቦታ",
      "stopovers_are_not_just_rest_stops_they": "ደው መበሊ ቦታታት ናይ ዕረፍቲ ቦታታት ጥራይ ኣይኮኑን፣ ንሳቶም ",
      "refueling_stations": "ናይ ነዳዲ-መመላእታ ጣብያታት",
      "critical_to_survival_a_migrating_warbl": " እዮም ንድሕነት ወሳኒ ዝኾኑ። ዝፈልስ warbler 75% ካብ ግዜ ፍልሰት ኣብ ደው መበሊ ቦታታት ከሕልፎ ይኽእል፣ ናይ ስብሒ ዕቑር ንምህናጽ ብዕብዳን እናበልዐ። ብሉጽ ናይ ደው መበሊ ቦታ መንበሪ ኣብ መንጎ ህይወትን ሞትን ፍልልይ ክኸውን ይኽእል።",
      "at_delaware_bay_over_1_million_shorebi": "ኣብ Delaware Bay፣ ካብ 1 ሚልዮን ንላዕሊ ናይ ገምገም ባሕሪ ኣዕዋፍ (Red Knots, Ruddy Turnstones, Sanderlings) ኣብ ግንቦት ኣብ ዝተነብረ ናይ ፍረስ-ጫማ ሽርጣን እንቋቑሖ ይምርኮሳ። ግዜ ፍጹም ክኸውን ኣለዎ: ኣዕዋፍ እቶም ናይ ፍረስ-ጫማ ሽርጣናት እንቋቑሖ ኣብ ዘንብሩሉ ልክዕ ግዜ ይበጽሓ። ብዝሒ ናይ ፍረስ-ጫማ ሽርጣናት እንተነኪዩ (ንመጻወዲ ብልዕሊ ዓቐን ብምግፋፍ)፣ ብምሉኡ ሰንሰለት ፍልሰት ይፈርስ።",
      "conservation_success_story_after_horse": "ናይ ዕቀባ ዓወት ዛንታ: ኣብ 2012 ናይ ፍረስ-ጫማ ሽርጣን ምእካብ ደረታት ድሕሪ ምእታው፣ ብዝሒ Red Knot ካብ ናይ ቅልውላው ትሑት 15,000 ናብ ካብ 50,000 ንላዕሊ ብ2025 ቀስ ብቐስ ክሓዊ ጀሚሩ።",
      "migration_physiology": "🦴 ፊዚዮሎጂ ፍልሰት",
      "migration_is_one_of_the_most_physicall": "ፍልሰት ኣብ መንግስቲ እንስሳታት ካብ ብኣካል ዝያዳ ዝጠልቡ ንጥፈታት ሓደ እዩ። ኣዕዋፍ ቅድሚ ምኻደን ዘደንቕ ናይ ኣካል ለውጥታት ይሓልፋ:",
      "hyperphagia": "ብልዕሊ ዓቐን ምብላዕ",
      "before_migration_birds_enter_a_feeding": "ቅድሚ ፍልሰት፣ ኣዕዋፍ ብልዕሊ ዓቐን ምብላዕ ናብ ዝብሃል ናይ ምብላዕ ዕብዳን ይኣትዋ፣ ካብ ልሙድ 2-3 ዕጽፊ ብዝኾነ ፍጥነት ይበልዓ። Blackpoll Warbler (12 ግራም) 8-12 ግራም ናይ ስብሒ ዕቑር ይውስኽ፣ ክብደት ኣካል ኣስታት ዕጽፊ ይገብር። እዚ ስብሒ ካብ 2,000 ማይል ንላዕሊ ንዝኾኑ ብዘይ ደው ምባል በረራታት ነዳዲ እዩ።",
      "organ_shrinkage": "ምጉዳል ኣካላት",
      "to_reduce_weight_migrating_birds_actua": "ክብደት ንምንካይ፣ ፈለስቲ ኣዕዋፍ ቅድሚ ምኻደን ናይ ምሕቃቕ ኣካላት (መዓንጣ፣ ጸላም ከብዲ፣ ጎሮሮ) ክሳብ 40% ብሓቂ የጉድላ። ናብ ደው መበሊ ቦታታት ምስ በጽሓ፣ ነዳዲ ንምምላእ ነዞም ኣካላት ቀልጢፈን ይሃንጽአን። እዚ “ፍኖታይፕ ተለዋዋጥነት” ኣብ ዓንዲ-ሕቖ ዘለዎም እንስሳታት ፍሉይ እዩ።",
      "hemoglobin": "ሄሞግሎቢን",
      "high_altitude_migrants_like_bar_headed": "ከም Bar-headed Geese (ኣብ ልዕሊ ሂማላያ 29,000 ጫማ ዝበርራ) ዝኣመሰላ ናይ ልዑል ቁመት ፈለስቲ ንኦክስጅን ዝያዳ ምስሓብ ዘለዎ ፍሉይ ሄሞግሎቢን ኣለወን። ጭዋድአን ተወሳኺ ሚዮግሎቢን ይሓዛ፣ ጽዕቀት ካፒላሪአን ድማ ካብ ናይ ትሑት ቦታ ዓሌታት ዕጽፊ እዩ።",
      "sleep_in_flight": "ኣብ በረራ ድቃስ",
      "some_birds_can_sleep_while_flying_usin": "ገለ ኣዕዋፍ እናበረራ ክድቅሳ ይኽእላ፣ “ናይ ፍርቂ-ንፍቀ ክቢ ድቃስ” ብምጥቃም — ኣብ ሓደ ግዜ ሓደ ንፍቀ ክቢ ኣእምሮ ብምዕጻው። Frigatebirds ኣብ ግዜ 10-መዓልቲ ናይ ውቅያኖስ-ምስጋር በረራታት ኣብ መዓልቲ 42 ደቒቕ ክድቅሳ ተመዝጊበን፣ ነፍሲ ወከፍ 12 ካልኢት ዝኾነ ንኣሽቱ-ድቃሳት እናወሰዳ።",
      "navigation_clock": "ሰዓት ኣንፈት",
      "birds_maintain_an_internal_circadian_c": "ኣዕዋፍ ዘደንቕ ልክዕነት ዘለዎ ውሽጣዊ ሰርካዲያን ሰዓት ይሕዛ። እዚ ሰዓት ኣብ ሰማይ ዘሎ ምንቅስቓስ ጸሓይ ይክሕስ (ግዜ-ዝክሕስ ናይ ጸሓይ ኮምፓስ) ንሆርሞናት ፍልሰት ዘለዓዕል ወቕታዊ ለውጥታት ንውሓት መዓልቲ ድማ ይከታተል።",
      "zugunruhe": "Zugunruhe",
      "zugunruhe_migration_restlessness_is_a_": "Zugunruhe (“ዘይምዕራፍ ፍልሰት”) ኣብ ቤት-ማእሰርቲ ዝተኣስራ ፈለስቲ ኣዕዋፍ ብተፈጥሮ ኣብ ዝፈልሳሉ ኣንፈት፣ ኣብ ዝፈልሳሉ ግዜ ክንቲት ዝንብዳሉ ናይ ባህሪ ኩነት እዩ። ብሆርሞን ዝድፋእን ብጅን ዝተመዝገበን እዩ። ናይ ፍልሰት ተመኩሮ ዘይብለን ብኢድ ዝዓበያ ኣዕዋፍ እኳ Zugunruhe የርእያ።",
      "species_comparison": "📊 ናይ ዓሌት ንጽጽር",
