      "sculpt_3d": "3D ቅረጽ",
      "contrast_2": "ንጽጽር",
      "color_wheel_hsl_hsv_complementary_pair": "መንኮርኮር ሕብሪ — HSL/HSV + መመላእታ ጽምድታት",
      "hue_0_360_around_the_wheel_saturation_": "መሰረታዊ ሕብሪ (0-360 ኣብ ዙርያ እቲ መንኮርኮር)፣ ምጽጋብ (ጽሬት)፣ ብርሃነት። መመላእታ ገጽ ንገጽ፣ ተመሳሰልቲ ጐረባብቲ፣ ስሉሳዊ ብ120° ርሕቀት። ኒውተን ኣብ 1666 ንህብረ-ጩራ ኣብ መንኮርኮር ኣቐመጦ።",
      "color_mixer_subtractive_vs_additive": "መሕወሲ ሕብሪ — ቀናሲ ኣንጻር ወሳኺ",
      "paint_and_print_subtractive_cmy_mixes_": "ቀለምን ሕትመትን = ቀናሲ (CMY ተሓዊሱ ናብ ጸላም የብጽሕ)፤ ብርሃንን ስክሪንን = ወሳኺ (RGB ተሓዊሱ ናብ ጻዕዳ የብጽሕ)። ሓደ ዓለም እዩ፣ ግን ፍጹም ዝተፈልየ ሒሳብ — ሓታሚት ብናይ K ሰሌዳታት ትሓስብ፣ ተለቪዥን ከኣ ብHz ትሓስብ።",
      "pixel_art_bitmap_craft_at_8_8_to_32_32": "ስነ ጥበብ ፒክስል — ካብ 8×8 ክሳብ 32×32 ዝበጽሕ ናይ ቢትማፕ ስራሕ",
      "each_pixel_is_a_deliberate_decision_ne": "ነፍሲ ወከፍ ፒክስል ብተግባር ዝተወስነ ውሳነ እዩ። ናይ NES ስፕራይታት ንጅግና ኣብ 16×16 ብ4 ሕብሪ ቤተ-ሕብሪ ብምእታዎም ይፍለጡ። ናይ Bresenham ናይ መስመር ኣልጎሪዝም ስየፍ መስመራት ብዘይ ዓሽራዊ ቁጽሪ ይስእል።",
      "symmetry_reflection_rotation_glide": "ምምጥጣን — መስትያት፣ ዙረት፣ ምንሽርታት",
      "bilateral_mirror_rotational_n_fold_poi": "ክልተ ጐናዊ (መስትያት)፣ ዙረታዊ (n-ዕጽፊ)፣ ነጥባዊ። እቶም 17 ጉጅለታት ናይ መንደቕ ወረቐት ንዝኾነ ተደጋጋሚ ናይ 2D ንድፊ ይመድቡ — ብምሉኡ ስራሕ Escher።",
      "spirograph_hypotrochoid_roulettes": "ስፓይሮግራፍ — ጥውይዋያት hypotrochoid",
      "a_small_circle_rolls_inside_a_big_one_": "ንእሽቶ ዓንኬል ኣብ ውሽጢ ዓቢ ይንከባለል፣ እቲ ብርዒ ከኣ ካብ ማእከል ርሒቑ ይቕመጥ። ጽምዶ ናይቶም ራድየሳት ቁጽሪ ቅጠላት ዕንባባ ይውስን፤ እቲ ርሕቀት ከኣ ውፍረት የቐምጥ። እታ መጻወቲ ኣብ 1965 ፓተንት ረኸበት፣ እቲ ሒሳብ ግን ካብ 1700ታት እዩ።",
      "generative_algorithm_randomness_as_art": "ወላዲ — ኣልጎሪዝም + ኣጋጣሚ ከም ስነ ጠቢብ",
      "sol_lewitt_wrote_instructions_the_wall": "Sol LeWitt መምርሒታት ጸሓፈ፤ እቲ ኣብ መንደቕ ዝሰርሖ ሰብ ከኣ ኣፈጻሚ ነበረ። ሎሚ፦ Processing፣ p5.js፣ Cinder። “እቲ ስነ ጠቢብ እቲ ሕጊ እዩ እምበር እቲ ውጽኢት ኣይኮነን።”",
      "spin_art_centripetal_physics_in_paint": "ስነ ጥበብ ምዝዋር — ኣብ ቀለም ዘሎ ናይ ናብ ማእከል ሳሓቢ ሓይሊ ፊዚክስ",
      "drop_paint_spin_watch_it_fling_outward": "ቀለም ኣንጠብጥብ፣ ኣዙር፣ ናብ ደገ ብጥውይዋይ ክድርበ ከሎ ተዓዘብ። Damien Hirst ናይ ምዝዋር ስእልታት ብምሻጥ ሚልዮናት ረኸበ። ልክዕ ከም ናይ ሰላጣ መንኮርኮር ዝኣመሰለ ፊዚክስ እዩ፤ F = mω²r።",
      "string_art_curves_from_straight_lines": "ስነ ጥበብ ፈትሊ — ካብ ትኹላት መስመራት ዝወጹ ጥውይዋያት",
      "connect_every_n_th_nail_an_envelope_cu": "ንነፍሲ ወከፍ n-ይ ሚስማር ኣራኽብ፤ ናይ ኤንቨሎፕ ጥውይዋይ ይቕልቀል። Mary Everest Boole ኣብ 1900 ኣቢሉ ከም ናይ ክፍሊ ትምህርቲ ሒሳብ ገይራ ኣተኣታተወቶ። እቲ ካብ ትኹላት መስመራት ዝወጽእ ካርድዮይድ ሎሚ'ውን የገርም እዩ።",
      "op_art_fooling_the_visual_system": "ኦፕ ስነ ጥበብ — ንስርዓት ምርኣይ ምትላል",
      "bridget_riley_s_moir_fields_vasarely_s": "ናይ Bridget Riley መዳያት ሞይረ፣ ናይ Vasarely ፍርግርጋት። ኣብ ቀልጢፉ ዝቀያየር ንጽጽር ናይ ሓንጎል ናይ ምንቅስቓስ መልለዪ ዳር ሕዋሳት ልዕሊ ዓቐን ይትኩሱ — እታ ገጽ ከኣ *ትንቀጥቀጥ* ትመስል።",
      "tessellation_the_17_wallpaper_groups": "ንጣፍ ንድፊ — እቶም 17 ጉጅለታት ናይ መንደቕ ወረቐት",
      "every_periodic_2d_tiling_fits_one_of_1": "ነፍሲ ወከፍ ግዜያዊ ዝድገም ናይ 2D ንጣፍ ካብቶም 17 ጉጅለታት ምምጥጣን ኣብ ሓደ ይኣቱ። Escher ኣብ 1936 ኣልሃምብራ ብምብጻሕ ነዚ ፈለጦ፤ ድሕሪኡ ነቲ ካታሎግ ንምውዳእ 30 ዓመታት ኣሕለፈ።",
      "fractal_self_similar_at_every_scale": "ፍራክታል — ኣብ ነፍሲ ወከፍ ደረጃ ንርእሱ ዝመስል",
      "mandelbrot_1975_cauliflower_coastlines": "Mandelbrot 1975። ዕንባባ ጎመን፣ ገማግም ባሕሪ፣ ስርወ-ደም፣ በርቂ፣ ናይ ሳንቡእ ኣየር ከረጺት — ኩሎም ፍራክታል እዮም። “ደመናታት ኩዕሶ ኣይኮኑን፣ ኣኽራን ኮን ኣይኮኑን፣ ቅርፍቲ'ውን ልስሉስ ኣይኮነን።”",
      "gradient_smooth_color_transitions": "ግራድየንት — ልስሉስ ምስግጋር ሕብሪ",
      "css_gives_you_linear_radial_and_conic_": "CSS ትኹላዊ፣ ዓንኬላውን ኮኒካውን ግራድየንታት ይህበኩም። ናይ ብሓቂ ቀስተ ደመና ቀጻሊ ህብረ-ጩራ ኣለዎ (ዝተፈላለዩ መስመራት የብሉን) — “እቶም 7 ሕብርታት ቀስተ ደመና” ኒውተን ብሙዚቃዊ ምኽንያት ዝወሰዶ ናይ ገዛእ ርእሱ ምርጫ እዩ ነይሩ።",
      "stereogram_3d_from_a_flat_page": "ስተርዮግራም — ካብ ጸፋሕ ገጽ ዝወጽእ 3D",
      "90s_magic_eye_craze_each_eye_sees_a_sl": "ናይ 90ታት ናይ Magic Eye ወረ። ነፍሲ ወከፍ ዓይኒ ቁሩብ ዝተቐየረ ስእሊ ትርኢ፤ ኣዒንትኻ ብግቡእ እንተ ኣሳገርካ ወይ እንተ ኣርሓቕካ ሓንጎልካ ነተን ክልተ ኣዋሃሂዱ ዕምቀት ይፈጥር። ኣስታት 5% ሰባት ብሓቂ ክርእይዎ ኣይክእሉን — ጌጋኦም ኣይኮነን።",
      "contrast_wcag_4_5_1_3_1_apca": "ንጽጽር — WCAG 4.5:1 / 3:1 / APCA",
      "wcag_2_1_normal_text_4_5_1_large_3_1_w": "WCAG 2.1፦ ንቡር ጽሑፍ 4.5:1፣ ዓቢ ጽሑፍ 3:1። ንስኻ ከተንብቦ እንተ ኸኣልካ'ውን ትሑት ንጽጽር ንትሑት ናይ ምርኣይ ዓቕሚ ንዘለዎም ኣንበብቲ ስለምንታይ ከም ዝጎድኦም። APCA (ተካኢ WCAG 3.0) ጥረ ናይ ብርሃን ጽምዶ ዘይኮነስ ኣገንዝቦኣዊ ብርሃነት ይጥቀም።",
      "harmony_lab_title": "ስምረት - ድምጺ፣ ጽምዶን ሕብርን",
      "harmony_lab_hint": "ዝሰማምዑን ዘይሰማምዑን ናይ ድምጺ ክፍተታት ኣወዳድሩ፣ ንጽምዶ ድግግሞሽ ምስ ንድፊ ኣራኽቡ፣ ንሙዚቃዊ ዝምድናታት ከኣ ናብ ናይ ምርኣይ ስምረት ተርጉሙ።",
